import{_ as e,o as i,c as a,a2 as o}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"银证转账入金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/hk-methods/bank-securities-transfer.md","filePath":"zh-CN/deposit/hk-methods/bank-securities-transfer.md"}'),r={name:"deposit/hk-methods/bank-securities-transfer.md"};function l(s,t,d,n,h,p){return i(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="银证转账入金" tabindex="-1">银证转账入金 <a class="header-anchor" href="#银证转账入金" aria-label="Permalink to &quot;银证转账入金&quot;">​</a></h1><p>银证转账是银行账户与证券账户之间的资金划转服务，可直接从银行将资金转入长桥证券账户，无需通过网银汇款，无需上传入金凭证。目前仅支持<strong>民生银行（香港）</strong>。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>港元（HKD）、美元（USD）</td></tr><tr><td>预计到账时间</td><td>工作日 09:00–15:00 约 5 分钟；其他时段约 1 个交易日</td></tr><tr><td>手续费</td><td>免费</td></tr></tbody></table><h2 id="第一步-开通银证关联" tabindex="-1">第一步：开通银证关联 <a class="header-anchor" href="#第一步-开通银证关联" aria-label="Permalink to &quot;第一步：开通银证关联&quot;">​</a></h2><p>首次使用需先在民生银行端完成关联开通。</p><p><strong>民生香港 App</strong></p><ol><li>打开民生香港 App → <strong>银证</strong> → 搜索「长桥证券（香港）有限公司」→ 点击「关联」</li><li>商户名称确认为「Long Bridge HK Limited」，关联账号填写长桥账户号码，点击「提交」</li><li>提示申请关联成功，等待审核</li></ol><p><strong>民生香港网上银行</strong></p><ol><li>登录民生银行个人网上银行 → <strong>银证转账 → 关联账户维护 → 新增关联账户</strong></li><li>商户名称选择「长桥证券（香港）有限公司 Long Bridge HK Limited」，关联账号填写长桥综合账户号码（如 H12345678）</li><li>插入 UKEY 并输入密码完成验证，等待审核</li></ol><h2 id="第二步-发起入金" tabindex="-1">第二步：发起入金 <a class="header-anchor" href="#第二步-发起入金" aria-label="Permalink to &quot;第二步：发起入金&quot;">​</a></h2><p><strong>民生香港 App</strong></p><ol><li>打开民生香港 App → <strong>银证</strong></li><li>选择已关联的「长桥证券（香港）有限公司」→「转账」→「银行转商户」</li><li>填写扣款账户和转账金额，确认后提交</li></ol><p><strong>民生香港网上银行</strong></p><ol><li>登录网上银行 → <strong>银证转账 → 转出转入 → 银行转至商户</strong></li><li>填写扣款账户和转账金额，确认后提交</li></ol><blockquote><p>民生网银交易时间：香港工作日 09:00–18:00，非工作时间及周六、周日和香港假期不接受转账。</p></blockquote><h2 id="同名账户与民生银行操作要求" tabindex="-1">同名账户与民生银行操作要求 <a class="header-anchor" href="#同名账户与民生银行操作要求" aria-label="Permalink to &quot;同名账户与民生银行操作要求&quot;">​</a></h2><ul><li>转账银行账户名必须与长桥证券账户名同名，不可使用他人或联名账户转账</li><li>需在民生银行登记有效手机号码、电邮地址及最新签发证件</li><li>银行通知「已汇出」不等于长桥已收款，资金到达后需结算与审批</li><li>香港公众假期不处理汇款业务，请预留时间</li><li>不接受直接存入现金</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit/methods-overview">入金方式总览</a> — 对比所有入金方式的预计到账时间与手续费</li><li><a href="/wiki/troubleshooting/deposit-not-received">入金未到账排查</a> — 超出预期时间未到账时的排查步骤</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit/how-to-choose-deposit-method">如何选择入金方式</a></li><li><a href="/wiki/deposit">入金</a></li></ul>',22)])])}const b=e(r,[["render",l]]);export{u as __pageData,b as default};
